tool.command:
mkdir -p pggb_out pggb_tmp && #set $delim_map = {'hash': '#', 'pipe': '|', 'underscore': '_', 'dot': '.'} #set $delim_char = $delim_map[str($exclude_delim)]
## pggb requires a bgzip-compressed input with samtools .fai/.gzi indices. ## Re-compress if user uploaded a plain-gzip or uncompressed FASTA. #if str($input_fasta.ext).endswith('gz') gunzip -c '$input_fasta' | bgzip -c -@ "\${GALAXY_SLOTS:-1}" > input.fa.gz && #else bgzip -c -@ "\${GALAXY_SLOTS:-1}" '$input_fasta' > input.fa.gz && #end if samtools faidx input.fa.gz &&
## Run pggb. Do not && to the next steps - vg deconstruct may fail ## (e.g. when --vcf-spec doesn't match graph sample names), and we ## still want to ship the GFA + .og which were produced earlier in ## the pipeline. The if-then-fi blocks below hard-error if the ## critical outputs are actually missing. pggb --input-fasta input.fa.gz --output-dir pggb_out --temp-dir pggb_tmp --threads "\${GALAXY_SLOTS:-1}" --segment-length $segment_length --map-pct-id $map_pct_id --n-haplotypes $n_haplotypes --min-match-len $min_match_len --n-mappings $n_mappings --mash-kmer $mash_kmer --exclude-delim '$delim_char' #if str($block_length).strip() --block-length $block_length #end if $no_splits #if str($poa_length_target).strip() --poa-length-target '$poa_length_target' #end if #if str($poa_params).strip() --poa-params '$poa_params' #end if #if str($poa_padding).strip() --poa-padding $poa_padding #end if $run_abpoa $global_poa $skip_normalization $skip_viz $stats $write_maf $multiqc #if str($vcf_spec).strip() --vcf-spec '$vcf_spec' #end if --names-with-params > pggb.log 2>&1 ;
pggb_exit=\$? ;
## Locate the output files (filenames carry hashes / params) echo "--- pggb exit=\$pggb_exit ---" ; ls -la pggb_out/ 2>/dev/null || true ;
gfa_file=\$(find pggb_out -maxdepth 1 \( -name '*.smooth.final.gfa' -o -name '*.smooth.fix.gfa' \) | head -1) ; og_file=\$(find pggb_out -maxdepth 1 \( -name '*.smooth.final.og' -o -name '*.smooth.fix.og' \) | head -1) ; lay_file=\$(find pggb_out -maxdepth 1 -name '*.lay' | head -1) ; draw_png=\$(find pggb_out -maxdepth 1 -name '*.draw.png' | head -1) ; viz_png=\$(find pggb_out -maxdepth 1 \( -name '*viz_multiqc.png' -o -name '*.viz_O*.png' \) | head -1) ; vcf_file=\$(find pggb_out -maxdepth 1 -name '*.vcf' | head -1) ; multiqc_html=\$(find pggb_out -maxdepth 1 -name 'multiqc_report.html' | head -1) ;
cp pggb.log '$output_log' ;
if [ -n "\$gfa_file" ]; then gzip -c "\$gfa_file" > '$output_gfa' ; else echo "ERROR: no final GFA in pggb_out/ (pggb exit=\$pggb_exit)" >&2; exit 1; fi ;
if [ -n "\$og_file" ]; then cp "\$og_file" '$output_og' ; else echo "ERROR: no final .og in pggb_out/ (pggb exit=\$pggb_exit)" >&2; exit 1; fi ;
#if not $skip_viz if [ -n "\$lay_file" ]; then cp "\$lay_file" '$output_lay' ; fi ; if [ -n "\$draw_png" ]; then cp "\$draw_png" '$output_layout_png' ; fi ; if [ -n "\$viz_png" ]; then cp "\$viz_png" '$output_viz_png' ; fi ; #end if
#if str($vcf_spec).strip() if [ -n "\$vcf_file" ]; then cp "\$vcf_file" '$output_vcf' ; fi ; #end if
#if $multiqc if [ -n "\$multiqc_html" ]; then cp "\$multiqc_html" '$output_multiqc' ; fi ; #end if
echo "DONE"
